#include <bits/stdc++.h>
using namespace std;
const int mod=998244353;
int n,h[1003],dp[1003][40004]; 
int ans;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&h[i]);
	ans=n;
	for(int i=1;i<=n;i++)
		for(int j=1;j<i;j++)
			dp[i][h[i]-h[j]+20000]+=dp[j][h[i]-h[j]+20000]+1,ans+=dp[j][h[i]-h[j]+20000]+1,ans%=mod,dp[i][h[i]-h[j]+20000]%=mod;
	printf("%d",ans);
	return 0;
}
